CODE_EXAMPLE:
public class RateLimiter {
  private int limit = 100;
  private int requestCount = 0;

  public bool AllowRequest() {
    if (requestCount >= limit) return false;
    requestCount++;
    return true;
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void AllowRequest_ReturnsFalse_WhenLimitReached() {
  var limiter = new RateLimiter();
  for (int i = 0; i < 100; i++) Assert.IsTrue(limiter.AllowRequest());
  Assert.IsFalse(limiter.AllowRequest());
}

[TestMethod]
public void AllowRequest_ReturnsTrue_ForAllowedRequests() {
  var limiter = new RateLimiter();
  Assert.IsTrue(limiter.AllowRequest());
  Assert.IsTrue(limiter.AllowRequest());
}
